import{_ as o,c as i,o as r,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.2.10: Sidecar Optimization, SDK Build Improvement","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.10.md","filePath":"en/changelog/v1.2.10.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.2.10.md"};function s(d,a,l,c,p,h){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-10-sidecar-optimization-sdk-build-improvement" tabindex="-1">v1.2.10: Sidecar Optimization, SDK Build Improvement <a class="header-anchor" href="#v1-2-10-sidecar-optimization-sdk-build-improvement" aria-label="Permalink to “v1.2.10: Sidecar Optimization, SDK Build Improvement”">​</a></h1><p><strong>Release Date</strong>: 2026-02-20</p><p>Minor version update optimizing desktop sidecar startup logic and improving SDK build output.</p><h2 id="🎯-one-sentence-summary" tabindex="-1">🎯 One-Sentence Summary <a class="header-anchor" href="#🎯-one-sentence-summary" aria-label="Permalink to “🎯 One-Sentence Summary”">​</a></h2><p>Desktop sidecar is smarter (only starts when not localhost); SDK build directory optimized.</p><hr><h2 id="✨-improvements" tabindex="-1">✨ Improvements <a class="header-anchor" href="#✨-improvements" aria-label="Permalink to “✨ Improvements”">​</a></h2><h3 id="desktop-sidecar-optimization" tabindex="-1">Desktop Sidecar Optimization <a class="header-anchor" href="#desktop-sidecar-optimization" aria-label="Permalink to “Desktop Sidecar Optimization”">​</a></h3><p>When the default server is localhost, <strong>sidecar process is no longer started</strong>.</p><p><strong>Benefits</strong>: Reduces unnecessary process startup, saves resources.</p><p><strong>Who benefits</strong>: Desktop users using local servers.</p><hr><h3 id="sdk-build-directory-optimization" tabindex="-1">SDK Build Directory Optimization <a class="header-anchor" href="#sdk-build-directory-optimization" aria-label="Permalink to “SDK Build Directory Optimization”">​</a></h3><p>SDK now builds to <code>dist/</code> directory instead of <code>dist/src/</code>.</p><p><strong>Benefits</strong>: Cleaner package structure, more intuitive import paths.</p><p><strong>Who benefits</strong>: Developers using OpenCode SDK.</p><hr><h2 id="📊-should-you-upgrade" tabindex="-1">📊 Should You Upgrade? <a class="header-anchor" href="#📊-should-you-upgrade" aria-label="Permalink to “📊 Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Developing SDK</td><td>✅ Recommended</td></tr><tr><td>Using local server</td><td>⚪ Optional upgrade</td></tr><tr><td>Regular user</td><td>⚪ Optional upgrade</td></tr></tbody></table><hr><h2 id="⬆️-upgrade-command" tabindex="-1">⬆️ Upgrade Command <a class="header-anchor" href="#⬆️-upgrade-command" aria-label="Permalink to “⬆️ Upgrade Command”">​</a></h2>',21),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="📚-documentation-update" tabindex="-1">📚 Documentation Update <a class="header-anchor" href="#📚-documentation-update" aria-label="Permalink to “📚 Documentation Update”">​</a></h2><h3 id="custom-tool-name-collision-precedence" tabindex="-1">Custom Tool Name Collision Precedence <a class="header-anchor" href="#custom-tool-name-collision-precedence" aria-label="Permalink to “Custom Tool Name Collision Precedence”">​</a></h3><p>Official documentation added a &quot;Tool Name Collision&quot; section, clarifying:</p><ul><li><strong>Custom tools override built-in tools with the same name</strong></li><li>For example: Creating <code>.opencode/tool/bash.ts</code> will replace the built-in <code>bash</code> tool</li><li>If you want to disable a built-in tool instead of overriding, use <a href="/en/5-advanced/05-permissions.html">Permission Configuration</a></li></ul><p><strong>Who benefits</strong>: Advanced users who need to customize or restrict built-in tool behavior.</p><hr><h2 id="📋-technical-details" tabindex="-1">📋 Technical Details <a class="header-anchor" href="#📋-technical-details" aria-label="Permalink to “📋 Technical Details”">​</a></h2><details><summary>Click to expand original Release Notes</summary><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h2><ul><li>Don&#39;t spawn sidecar if default is localhost server</li></ul><h2 id="sdk" tabindex="-1">SDK <a class="header-anchor" href="#sdk" aria-label="Permalink to “SDK”">​</a></h2><ul><li>Build SDK to dist/ instead of dist/src</li></ul><p><strong>Thank you to 1 community contributor:</strong></p><ul><li>@rmk40: docs: clarify tool name collision precedence</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',11)])])}const g=o(n,[["render",s]]);export{u as __pageData,g as default};
